<?php
declare(strict_types=1);
final class UpdateVehiculoService implements UpdateVehiculoUseCase { private UpdateVehiculoPort $updatePort; private GetVehiculoByIdPort $idPort; private GetVehiculoByPlacaPort $placaPort; public function __construct(UpdateVehiculoPort $updatePort, GetVehiculoByIdPort $idPort, GetVehiculoByPlacaPort $placaPort){$this->updatePort=$updatePort;$this->idPort=$idPort;$this->placaPort=$placaPort;} public function execute(UpdateVehiculoCommand $command): VehiculoModel { $id = new VehiculoId((string) $command->get('id')); if ($this->idPort->getById($id)===null){ throw VehiculoNotFoundException::becauseIdWasNotFound($id->value()); } $placa = new VehiculoPlaca((string) $command->get('placa')); $same = $this->placaPort->getByPlaca($placa); if ($same!==null && !$same->id()->equals($id)){ throw VehiculoAlreadyExistsException::becausePlacaAlreadyExists($placa->value()); } return $this->updatePort->update(VehiculoApplicationMapper::fromUpdateCommandToModel($command)); } }
